const b = $input.first().json.body || {};

// Los archivos llegan ya en el propio aviso (base64), directos desde el
// formulario — no hace falta ir a buscarlos a ningún sitio ni usar ninguna key.
const archivos = Array.isArray(b.archivos) ? b.archivos : [];

const attachments = archivos
  .filter(f => f?.content)
  .map(f => ({ filename: f.nombre || 'archivo', content: f.content }));

if (b.logo?.content) {
  attachments.push({ filename: b.logo.nombre || 'logo', content: b.logo.content });
}

const nombreAgencia = b.nombre_agencia || 'Agencia';
const subject = `Nueva ficha de alta — ${nombreAgencia}`;

const totalEsperado = archivos.length + (b.logo ? 1 : 0);

const html = `
  <p><strong>${nombreAgencia}</strong> acaba de enviar su ficha de alta.</p>
  <ul>
    <li><strong>Razón social:</strong> ${b.razon_social || '—'}</li>
    <li><strong>NIF/CIF:</strong> ${b.nif || '—'}</li>
    <li><strong>Persona que rellena:</strong> ${b.persona_rellena || '—'}</li>
    <li><strong>Email de contacto:</strong> ${b.email_contacto || '—'}</li>
    <li><strong>Teléfono de administración:</strong> ${b.telefono_admin || '—'}</li>
    <li><strong>Fecha:</strong> ${b.fecha || '—'}</li>
    <li><strong>Archivos adjuntos a este email:</strong> ${attachments.length} de ${totalEsperado}</li>
  </ul>
  <p><a href="https://automanize.com/alta-agencia-admin.html">Ver el detalle en el panel</a> (por si falta algún adjunto)</p>
`;

return [{
  json: {
    from: 'onboarding@automanize.com',
    to: 'martinmunozinfo@gmail.com',
    subject,
    html,
    attachments,
  }
}];
